def insert(k, v, len, min, max, kveq, len1, min1, max1, kveq1):
    kveq_prop_maintained = And(kveq == 1, k == v)
    return And(
        len1 == len + 1,
        min1 == If(len == 0, k, If(k < min, k, min)),
        max1 == If(len == 0, k, If(k > max, k, max)),
        kveq1 == If(kveq_prop_maintained, 1, 0)
    )

def find(k, len, min, max, kveq, ret1):
    precondition = And(kveq == 1, min <= k, k <= max)
    return Implies(precondition, ret1 == k)

